import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { toast } from 'react-hot-toast';

const Perfil: React.FC = () => {
  const { user, updateUser } = useAuth();
  const [loading, setLoading] = useState(false);
  const [editing, setEditing] = useState(false);
  const [formData, setFormData] = useState({
    nome: user?.nome || '',
    email: user?.email || '',
    localizacao: user?.perfil?.localizacao || '',
    // Campos específicos por papel de usuário
    tipo: user?.perfil?.tipo || '',
    areas_ensino: user?.perfil?.areas_ensino || [],
    qtd_alunos: user?.perfil?.qtd_alunos || '',
    empresa: user?.perfil?.empresa || '',
    setor: user?.perfil?.setor || '',
    porte: user?.perfil?.porte || '',
    areas_atuacao: user?.perfil?.areas_atuacao || [],
    areas_interesse: user?.perfil?.areas_interesse || [],
    programas_sociais: user?.perfil?.programas_sociais || []
  });

  useEffect(() => {
    if (user) {
      setFormData({
        nome: user.nome || '',
        email: user.email || '',
        localizacao: user.perfil?.localizacao || '',
        // Campos específicos por papel de usuário
        tipo: user.perfil?.tipo || '',
        areas_ensino: user.perfil?.areas_ensino || [],
        qtd_alunos: user.perfil?.qtd_alunos || '',
        empresa: user.perfil?.empresa || '',
        setor: user.perfil?.setor || '',
        porte: user.perfil?.porte || '',
        areas_atuacao: user.perfil?.areas_atuacao || [],
        areas_interesse: user.perfil?.areas_interesse || [],
        programas_sociais: user.perfil?.programas_sociais || []
      });
    }
  }, [user]);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleArrayChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    // Converter string em array (cada linha é um item)
    const arrayValue = value.split('\n').map(item => item.trim()).filter(item => item);
    setFormData(prev => ({ ...prev, [name]: arrayValue }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    
    try {
      await updateUser(formData);
      toast.success('Perfil atualizado com sucesso!');
      setEditing(false);
    } catch (error) {
      console.error('Erro ao atualizar perfil:', error);
      toast.error('Erro ao atualizar perfil. Tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  if (!user) {
    return <div className="text-center py-12">Usuário não encontrado</div>;
  }

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="mb-8 flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold text-cursor-text-primary">Meu Perfil</h1>
          <p className="text-cursor-text-secondary mt-1">
            Visualize e edite suas informações
          </p>
        </div>
        <div className="flex space-x-3">
          {!editing ? (
            <button
              onClick={() => setEditing(true)}
              className="px-4 py-2 border border-cursor-primary rounded-md text-cursor-primary bg-white hover:bg-cursor-primary/10"
            >
              Editar Perfil
            </button>
          ) : (
            <button
              onClick={() => setEditing(false)}
              className="px-4 py-2 border border-cursor-border rounded-md text-cursor-text-primary bg-white hover:bg-cursor-bg"
              disabled={loading}
            >
              Cancelar
            </button>
          )}
          <Link
            to="/alterar-senha"
            className="px-4 py-2 bg-cursor-primary text-white rounded-md hover:bg-cursor-primary-dark"
          >
            Alterar Senha
          </Link>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow-cursor overflow-hidden">
        {editing ? (
          <form onSubmit={handleSubmit} className="p-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Informações básicas */}
              <div className="space-y-4">
                <h3 className="text-lg font-medium text-cursor-text-primary mb-4">Informações Básicas</h3>
                
                <div>
                  <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Nome
                  </label>
                  <input
                    type="text"
                    name="nome"
                    value={formData.nome}
                    onChange={handleChange}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                    required
                  />
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Email
                  </label>
                  <input
                    type="email"
                    value={formData.email}
                    disabled
                    className="w-full p-3 rounded-lg bg-gray-100 text-cursor-text-secondary border border-cursor-border"
                  />
                  <p className="text-xs text-cursor-text-tertiary mt-1">
                    O email não pode ser alterado
                  </p>
                </div>
                
                <div>
                  <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Localização
                  </label>
                  <input
                    type="text"
                    name="localizacao"
                    value={formData.localizacao}
                    onChange={handleChange}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                  />
                </div>
              </div>
              
              {/* Campos específicos baseados no papel */}
              <div className="space-y-4">
                <h3 className="text-lg font-medium text-cursor-text-primary mb-4">Informações Específicas</h3>
                
                {user.papel === 'instituicao_ensino' && (
                  <>
                    <div>
                      <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                        Tipo de Instituição
                      </label>
                      <input
                        type="text"
                        name="tipo"
                        value={formData.tipo}
                        onChange={handleChange}
                        className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                        Número de Alunos
                      </label>
                      <input
                        type="number"
                        name="qtd_alunos"
                        value={formData.qtd_alunos}
                        onChange={handleChange}
                        className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                        Áreas de Ensino (uma por linha)
                      </label>
                      <textarea
                        name="areas_ensino"
                        value={formData.areas_ensino.join('\n')}
                        onChange={handleArrayChange}
                        rows={4}
                        className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                      />
                    </div>
                  </>
                )}
                
                {user.papel === 'chefe_empresa' && (
                  <>
                    <div>
                      <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                        Nome da Empresa
                      </label>
                      <input
                        type="text"
                        name="empresa"
                        value={formData.empresa}
                        onChange={handleChange}
                        className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                        Setor
                      </label>
                      <input
                        type="text"
                        name="setor"
                        value={formData.setor}
                        onChange={handleChange}
                        className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                        Porte da Empresa
                      </label>
                      <input
                        type="text"
                        name="porte"
                        value={formData.porte}
                        onChange={handleChange}
                        className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                      />
                    </div>
                    
                    <div>
                      <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                        Áreas de Atuação (uma por linha)
                      </label>
                      <textarea
                        name="areas_atuacao"
                        value={formData.areas_atuacao.join('\n')}
                        onChange={handleArrayChange}
                        rows={4}
                        className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                      />
                    </div>
                  </>
                )}
                
                {/* Campos comuns para todos ou específicos para instituição contratante */}
                {(user.papel === 'instituicao_contratante' || user.papel === 'chefe_empresa') && (
                  <div>
                    <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                      Áreas de Interesse (uma por linha)
                    </label>
                    <textarea
                      name="areas_interesse"
                      value={formData.areas_interesse.join('\n')}
                      onChange={handleArrayChange}
                      rows={4}
                      className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                    />
                  </div>
                )}
                
                {user.papel === 'instituicao_contratante' && (
                  <div>
                    <label className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                      Programas Sociais (um por linha)
                    </label>
                    <textarea
                      name="programas_sociais"
                      value={formData.programas_sociais.join('\n')}
                      onChange={handleArrayChange}
                      rows={4}
                      className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:outline-none"
                    />
                  </div>
                )}
              </div>
            </div>
            
            <div className="flex justify-end mt-6">
              <button
                type="submit"
                className="px-4 py-2 bg-cursor-primary text-white rounded-md hover:bg-cursor-primary-dark flex items-center"
                disabled={loading}
              >
                {loading ? (
                  <>
                    <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Salvando...
                  </>
                ) : 'Salvar Alterações'}
              </button>
            </div>
          </form>
        ) : (
          <div className="p-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Informações básicas */}
              <div>
                <h3 className="text-lg font-medium text-cursor-text-primary mb-4">Informações Básicas</h3>
                
                <dl className="space-y-3">
                  <div>
                    <dt className="text-sm font-medium text-cursor-text-tertiary">Nome</dt>
                    <dd className="mt-1 text-cursor-text-primary">{user.nome}</dd>
                  </div>
                  
                  <div>
                    <dt className="text-sm font-medium text-cursor-text-tertiary">Email</dt>
                    <dd className="mt-1 text-cursor-text-primary">{user.email}</dd>
                  </div>
                  
                  <div>
                    <dt className="text-sm font-medium text-cursor-text-tertiary">Tipo de Usuário</dt>
                    <dd className="mt-1 text-cursor-text-primary">
                      {user.papel === 'instituicao_ensino' ? 'Instituição de Ensino' : 
                       user.papel === 'chefe_empresa' ? 'Chefe de Empresa' : 
                       'Instituição Contratante'}
                    </dd>
                  </div>
                  
                  <div>
                    <dt className="text-sm font-medium text-cursor-text-tertiary">Localização</dt>
                    <dd className="mt-1 text-cursor-text-primary">{user.perfil?.localizacao || '-'}</dd>
                  </div>
                </dl>
              </div>
              
              {/* Informações específicas */}
              <div>
                <h3 className="text-lg font-medium text-cursor-text-primary mb-4">Informações Específicas</h3>
                
                {user.papel === 'instituicao_ensino' && (
                  <dl className="space-y-3">
                    <div>
                      <dt className="text-sm font-medium text-cursor-text-tertiary">Tipo de Instituição</dt>
                      <dd className="mt-1 text-cursor-text-primary">{user.perfil?.tipo || '-'}</dd>
                    </div>
                    
                    <div>
                      <dt className="text-sm font-medium text-cursor-text-tertiary">Número de Alunos</dt>
                      <dd className="mt-1 text-cursor-text-primary">{user.perfil?.qtd_alunos || '-'}</dd>
                    </div>
                    
                    <div>
                      <dt className="text-sm font-medium text-cursor-text-tertiary">Áreas de Ensino</dt>
                      <dd className="mt-1">
                        {user.perfil?.areas_ensino && user.perfil.areas_ensino.length > 0 ? (
                          <ul className="list-disc pl-5">
                            {user.perfil.areas_ensino.map((area: string, index: number) => (
                              <li key={index} className="text-cursor-text-primary">{area}</li>
                            ))}
                          </ul>
                        ) : (
                          <span className="text-cursor-text-secondary">Não informado</span>
                        )}
                      </dd>
                    </div>
                  </dl>
                )}
                
                {user.papel === 'chefe_empresa' && (
                  <dl className="space-y-3">
                    <div>
                      <dt className="text-sm font-medium text-cursor-text-tertiary">Empresa</dt>
                      <dd className="mt-1 text-cursor-text-primary">{user.perfil?.empresa || '-'}</dd>
                    </div>
                    
                    <div>
                      <dt className="text-sm font-medium text-cursor-text-tertiary">Setor</dt>
                      <dd className="mt-1 text-cursor-text-primary">{user.perfil?.setor || '-'}</dd>
                    </div>
                    
                    <div>
                      <dt className="text-sm font-medium text-cursor-text-tertiary">Porte da Empresa</dt>
                      <dd className="mt-1 text-cursor-text-primary">{user.perfil?.porte || '-'}</dd>
                    </div>
                    
                    <div>
                      <dt className="text-sm font-medium text-cursor-text-tertiary">Áreas de Atuação</dt>
                      <dd className="mt-1">
                        {user.perfil?.areas_atuacao && user.perfil.areas_atuacao.length > 0 ? (
                          <ul className="list-disc pl-5">
                            {user.perfil.areas_atuacao.map((area: string, index: number) => (
                              <li key={index} className="text-cursor-text-primary">{area}</li>
                            ))}
                          </ul>
                        ) : (
                          <span className="text-cursor-text-secondary">Não informado</span>
                        )}
                      </dd>
                    </div>
                  </dl>
                )}
                
                {(user.papel === 'instituicao_contratante' || user.papel === 'chefe_empresa') && (
                  <div>
                    <dt className="text-sm font-medium text-cursor-text-tertiary">Áreas de Interesse</dt>
                    <dd className="mt-1">
                      {user.perfil?.areas_interesse && user.perfil.areas_interesse.length > 0 ? (
                        <ul className="list-disc pl-5">
                          {user.perfil.areas_interesse.map((area: string, index: number) => (
                            <li key={index} className="text-cursor-text-primary">{area}</li>
                          ))}
                        </ul>
                      ) : (
                        <span className="text-cursor-text-secondary">Não informado</span>
                      )}
                    </dd>
                  </div>
                )}
                
                {user.papel === 'instituicao_contratante' && (
                  <div className="mt-3">
                    <dt className="text-sm font-medium text-cursor-text-tertiary">Programas Sociais</dt>
                    <dd className="mt-1">
                      {user.perfil?.programas_sociais && user.perfil.programas_sociais.length > 0 ? (
                        <ul className="list-disc pl-5">
                          {user.perfil.programas_sociais.map((programa: string, index: number) => (
                            <li key={index} className="text-cursor-text-primary">{programa}</li>
                          ))}
                        </ul>
                      ) : (
                        <span className="text-cursor-text-secondary">Não informado</span>
                      )}
                    </dd>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export default Perfil;
